// Formatear input para WhatsApp
const wppData = $('une_data_wpp').first().json;
const dataPerfil = $('get-perfil').first().json;

// Recuperar memoria de forma segura
const inputData = $input.first().json;
const memoria_contexto_array = inputData.ChatMemory || [];

// Obtener etapa actual de forma segura - priorizar dataPerfil sobre historial
const etapa_actual = dataPerfil?.etapa_actual 
  || (memoria_contexto_array.length > 0 
    ? memoria_contexto_array[memoria_contexto_array.length - 1].etapa 
    : null);

// CONSTRUIR BLOQUE DE PERFIL CONSOLIDADO
let bloque_perfil = "";
if (dataPerfil && dataPerfil.telefono) {
  const campos = [
    dataPerfil.nombre        ? `Nombre: ${dataPerfil.nombre}` : null,
    dataPerfil.email         ? `Email: ${dataPerfil.email}` : null,
    dataPerfil.origen        ? `Origen: ${dataPerfil.origen}` : null,
    dataPerfil.domicilio     ? `Domicilio: ${dataPerfil.domicilio}` : null,
    dataPerfil.presupuesto   ? `Presupuesto: ${dataPerfil.presupuesto}` : null,
    dataPerfil.grupo_familiar ? `Grupo familiar: ${dataPerfil.grupo_familiar}` : null,
    dataPerfil.credito_bancario !== null && dataPerfil.credito_bancario !== undefined
      ? `Crédito bancario: ${dataPerfil.credito_bancario ? 'Sí' : 'No'}` : null,
    dataPerfil.modelos_interes?.length 
      ? `Modelos de interés: ${dataPerfil.modelos_interes.join(', ')}` : null,
    dataPerfil.etapa_actual  ? `Etapa actual: ${dataPerfil.etapa_actual}` : null,
  ].filter(Boolean);

  if (campos.length > 0) {
    bloque_perfil = `=== PERFIL CONSOLIDADO DEL CLIENTE ===\n${campos.join('\n')}\n======================================\n\n`;
  }
}

// CONVERTIR ARRAY A TEXTO PLANO para que el AI Agent lo reconozca
let memoria_contexto = "";
if (memoria_contexto_array && memoria_contexto_array.length > 0) {
  const historial = memoria_contexto_array
    .map(item => `${item.created_at}: ${item.mensaje}`)
    .join('\n');
  memoria_contexto = bloque_perfil + historial;
} else {
  memoria_contexto = bloque_perfil; // Solo perfil, sin historial previo
}

// Extraer información del mensaje de WhatsApp
const message = wppData.messages[0];
const contact = wppData.contacts[0];
const chatInput = wppData.mensajeUsuario;
const sessionId = message.from;

// Obtener nombre de usuario - priorizar dataPerfil sobre historial
let userName = dataPerfil?.nombre 
  || wppData.contacts[0]?.profile?.name 
  || 'Cliente';

const celular = message.from;
const normalizedNumber = celular.replace(/^54/, "54");

// Formatear para el AI Agent
const formattedInput = {
  sessionId: sessionId,
  action: 'sendMessage',
  chatInput: chatInput,
  etapa_actual,
  userContext: {
    name: userName,
    userId: message.from,
    chatId: message.from,
    phoneNumberId: wppData.metadata.phone_number_id,
    displayPhoneNumber: wppData.metadata.display_phone_number,
    telefono_origen: normalizedNumber,
    messageId: message.id,
    timestamp: message.timestamp,
    platform: 'whatsapp',
    contexto_historial: memoria_contexto    
  }
};

return { json: formattedInput };

